// 7-Segment Counter with Potentiometer & Buttons
// Segments: A=D2, B=D3, C=D4, D=D5, E=D6, F=D7, G=D8
// Buttons: Add=D9, Sub=D10
// Pot: A0 (analog)

const int SEG_A = 2;
const int SEG_B = 3;
const int SEG_C = 4;
const int SEG_D = 5;
const int SEG_E = 6;
const int SEG_F = 7;
const int SEG_G = 8;
const int ADD_BTN = 9;
const int SUB_BTN = 10;
const int POT_PIN = 15;  // A1

int counter = 0;
int lastAddState = HIGH;
int lastSubState = HIGH;

void setup() {
  pinMode(SEG_A, OUTPUT);
  pinMode(SEG_B, OUTPUT);
  pinMode(SEG_C, OUTPUT);
  pinMode(SEG_D, OUTPUT);
  pinMode(SEG_E, OUTPUT);
  pinMode(SEG_F, OUTPUT);
  pinMode(SEG_G, OUTPUT);
  pinMode(ADD_BTN, INPUT_PULLUP);
  pinMode(SUB_BTN, INPUT_PULLUP);
  pinMode(POT_PIN, INPUT);
}

void displayDigit(int digit) {
  // Turn off all segments
  digitalWrite(SEG_A, LOW);
  digitalWrite(SEG_B, LOW);
  digitalWrite(SEG_C, LOW);
  digitalWrite(SEG_D, LOW);
  digitalWrite(SEG_E, LOW);
  digitalWrite(SEG_F, LOW);
  digitalWrite(SEG_G, LOW);

  // Set segments for each digit (0-9)
  if (digit == 0) {
    digitalWrite(SEG_A, HIGH);
    digitalWrite(SEG_B, HIGH);
    digitalWrite(SEG_C, HIGH);
    digitalWrite(SEG_D, HIGH);
    digitalWrite(SEG_E, HIGH);
    digitalWrite(SEG_F, HIGH);
  } else if (digit == 1) {
    digitalWrite(SEG_B, HIGH);
    digitalWrite(SEG_C, HIGH);
  } else if (digit == 2) {
    digitalWrite(SEG_A, HIGH);
    digitalWrite(SEG_B, HIGH);
    digitalWrite(SEG_D, HIGH);
    digitalWrite(SEG_E, HIGH);
    digitalWrite(SEG_G, HIGH);
  } else if (digit == 3) {
    digitalWrite(SEG_A, HIGH);
    digitalWrite(SEG_B, HIGH);
    digitalWrite(SEG_C, HIGH);
    digitalWrite(SEG_D, HIGH);
    digitalWrite(SEG_G, HIGH);
  } else if (digit == 4) {
    digitalWrite(SEG_B, HIGH);
    digitalWrite(SEG_C, HIGH);
    digitalWrite(SEG_F, HIGH);
    digitalWrite(SEG_G, HIGH);
  } else if (digit == 5) {
    digitalWrite(SEG_A, HIGH);
    digitalWrite(SEG_C, HIGH);
    digitalWrite(SEG_D, HIGH);
    digitalWrite(SEG_F, HIGH);
    digitalWrite(SEG_G, HIGH);
  } else if (digit == 6) {
    digitalWrite(SEG_A, HIGH);
    digitalWrite(SEG_C, HIGH);
    digitalWrite(SEG_D, HIGH);
    digitalWrite(SEG_E, HIGH);
    digitalWrite(SEG_F, HIGH);
    digitalWrite(SEG_G, HIGH);
  } else if (digit == 7) {
    digitalWrite(SEG_A, HIGH);
    digitalWrite(SEG_B, HIGH);
    digitalWrite(SEG_C, HIGH);
  } else if (digit == 8) {
    digitalWrite(SEG_A, HIGH);
    digitalWrite(SEG_B, HIGH);
    digitalWrite(SEG_C, HIGH);
    digitalWrite(SEG_D, HIGH);
    digitalWrite(SEG_E, HIGH);
    digitalWrite(SEG_F, HIGH);
    digitalWrite(SEG_G, HIGH);
  } else if (digit == 9) {
    digitalWrite(SEG_A, HIGH);
    digitalWrite(SEG_B, HIGH);
    digitalWrite(SEG_C, HIGH);
    digitalWrite(SEG_D, HIGH);
    digitalWrite(SEG_F, HIGH);
    digitalWrite(SEG_G, HIGH);
  }
}

void loop() {
  // Read potentiometer (0-1023 maps to 0-9)
  int potValue = analogRead(POT_PIN);
  int potCounter = potValue / 114;  // 1023 / 9 ≈ 114
  if (potCounter > 9) {
    potCounter = 9;
  }

  // Read add button
  int addState = digitalRead(ADD_BTN);
  if (addState == LOW && lastAddState == HIGH) {
    if (counter < 9) {
      counter++;
    }
    delay(50);  // Debounce
  }
  lastAddState = addState;

  // Read subtract button
  int subState = digitalRead(SUB_BTN);
  if (subState == LOW && lastSubState == HIGH) {
    if (counter > 0) {
      counter--;
    }
    delay(50);  // Debounce
  }
  lastSubState = subState;

  // Use potentiometer value if changed significantly
  if (potCounter != counter) {
    counter = potCounter;
  }

  // Display current counter value
  displayDigit(counter);

  delay(10);
}

